// Merge all statistics into metrics array
const workflowStats = $input.all()[0].json;
const leadStats = $input.all()[1].json;
const docStats = $input.all()[2].json;
const taskStats = $input.all()[3].json;
const dlqStats = $input.all()[4].json;
const systemStats = $input.all()[5].json;

const metrics = [
  { metric_name: 'workflow_executions_total', metric_value: workflowStats.total_executions || 0, metric_unit: 'count', tags: { type: 'workflow' } },
  { metric_name: 'workflow_executions_success', metric_value: workflowStats.successful || 0, metric_unit: 'count', tags: { type: 'workflow', status: 'success' } },
  { metric_name: 'workflow_executions_failed', metric_value: workflowStats.failed || 0, metric_unit: 'count', tags: { type: 'workflow', status: 'failed' } },
  { metric_name: 'avg_execution_time_ms', metric_value: workflowStats.avg_duration_ms || 0, metric_unit: 'ms', tags: { type: 'performance' } },
  { metric_name: 'min_execution_time_ms', metric_value: workflowStats.min_duration_ms || 0, metric_unit: 'ms', tags: { type: 'performance' } },
  { metric_name: 'max_execution_time_ms', metric_value: workflowStats.max_duration_ms || 0, metric_unit: 'ms', tags: { type: 'performance' } },
  { metric_name: 'leads_total', metric_value: leadStats.total_leads || 0, metric_unit: 'count', tags: { type: 'business', entity: 'lead' } },
  { metric_name: 'leads_new', metric_value: leadStats.new_leads || 0, metric_unit: 'count', tags: { type: 'business', entity: 'lead', status: 'new' } },
  { metric_name: 'leads_enriched', metric_value: leadStats.enriched_leads || 0, metric_unit: 'count', tags: { type: 'business', entity: 'lead', status: 'enriched' } },
  { metric_name: 'leads_routed', metric_value: leadStats.routed_leads || 0, metric_unit: 'count', tags: { type: 'business', entity: 'lead', status: 'routed' } },
  { metric_name: 'documents_total', metric_value: docStats.total_docs || 0, metric_unit: 'count', tags: { type: 'business', entity: 'document' } },
  { metric_name: 'documents_processing', metric_value: docStats.processing_docs || 0, metric_unit: 'count', tags: { type: 'business', entity: 'document', status: 'processing' } },
  { metric_name: 'documents_valid', metric_value: docStats.valid_docs || 0, metric_unit: 'count', tags: { type: 'business', entity: 'document', status: 'valid' } },
  { metric_name: 'documents_invalid', metric_value: docStats.invalid_docs || 0, metric_unit: 'count', tags: { type: 'business', entity: 'document', status: 'invalid' } },
  { metric_name: 'tasks_total', metric_value: taskStats.total_tasks || 0, metric_unit: 'count', tags: { type: 'business', entity: 'task' } },
  { metric_name: 'tasks_pending', metric_value: taskStats.pending_tasks || 0, metric_unit: 'count', tags: { type: 'business', entity: 'task', status: 'pending' } },
  { metric_name: 'tasks_in_progress', metric_value: taskStats.in_progress_tasks || 0, metric_unit: 'count', tags: { type: 'business', entity: 'task', status: 'in_progress' } },
  { metric_name: 'tasks_completed', metric_value: taskStats.completed_tasks || 0, metric_unit: 'count', tags: { type: 'business', entity: 'task', status: 'completed' } },
  { metric_name: 'tasks_overdue', metric_value: taskStats.overdue_tasks || 0, metric_unit: 'count', tags: { type: 'business', entity: 'task', status: 'overdue' } },
  { metric_name: 'dlq_total', metric_value: dlqStats.dlq_count || 0, metric_unit: 'count', tags: { type: 'system', queue: 'dead_letter' } },
  { metric_name: 'dlq_retryable', metric_value: dlqStats.retryable_count || 0, metric_unit: 'count', tags: { type: 'system', queue: 'dead_letter', status: 'retryable' } },
  { metric_name: 'dlq_failed', metric_value: dlqStats.failed_count || 0, metric_unit: 'count', tags: { type: 'system', queue: 'dead_letter', status: 'failed' } },
  { metric_name: 'disk_usage_percent', metric_value: systemStats.disk_usage_percent || 0, metric_unit: 'percent', tags: { type: 'resource', resource: 'disk' } },
  { metric_name: 'db_connections', metric_value: systemStats.db_connections || 0, metric_unit: 'count', tags: { type: 'resource', resource: 'database' } },
  { metric_name: 'active_executions', metric_value: systemStats.active_executions || 0, metric_unit: 'count', tags: { type: 'resource', resource: 'execution' } }
];

return metrics.map(metric => ({ json: metric }));
